func (w *ServerInterfaceWrapper) GetProjectLimits(ctx echo.Context) error {
	var err error
	// ------------- Path parameter "organizationID" -------------
	var organizationID OrganizationID

	err = runtime.BindStyledParameterWithOptions("simple", "organizationID", ctx.Param("organizationID"), &organizationID, runtime.BindStyledParameterOptions{ParamLocation: runtime.ParamLocationPath, Explode: false, Required: true})
	if err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, fmt.Sprintf("Invalid format for parameter organizationID: %s", err))
	}

	// ------------- Path parameter "projectID" -------------
	var projectID string

	err = runtime.BindStyledParameterWithOptions("simple", "projectID", ctx.Param("projectID"), &projectID, runtime.BindStyledParameterOptions{ParamLocation: runtime.ParamLocationPath, Explode: false, Required: true})
	if err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, fmt.Sprintf("Invalid format for parameter projectID: %s", err))
	}

	ctx.Set(XataScopes, []string{"project:read"})

	// Invoke the callback with all the unmarshaled arguments
	err = w.Handler.GetProjectLimits(ctx, organizationID, projectID)
	return err
}

// ListRegions converts echo context to params.
func (w *ServerInterfaceWrapper) ListRegions(ctx echo.Context) error {
	var err error
	// ------------- Path parameter "organizationID" -------------
	var organizationID OrganizationID

	err = runtime.BindStyledParameterWithOptions("simple", "organizationID", ctx.Param("organizationID"), &organizationID, runtime.BindStyledParameterOptions{ParamLocation: runtime.ParamLocationPath, Explode: false, Required: true})
	if err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, fmt.Sprintf("Invalid format for parameter organizationID: %s", err))
	}

	ctx.Set(XataScopes, []string{"project:read"})

	// Invoke the callback with all the unmarshaled arguments
	err = w.Handler.ListRegions(ctx, organizationID)
	return err
}

// This is a simple interface which specifies echo.Route addition functions which
// are present on both echo.Echo and echo.Group, since we want to allow using
// either of them for path registration
type EchoRouter interface {
	CONNECT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	DELETE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	GET(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	HEAD(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	OPTIONS(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PATCH(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	POST(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	PUT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
	TRACE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) *echo.Route
}

// RegisterHandlers adds each server route to the EchoRouter.
func RegisterHandlers(router EchoRouter, si ServerInterface) {
	RegisterHandlersWithBaseURL(router, si, "")
}

// Registers handlers, and prepends BaseURL to the paths, so that the paths
// can be served under a prefix.
func RegisterHandlersWithBaseURL(router EchoRouter, si ServerInterface, baseURL string) {

	wrapper := ServerInterfaceWrapper{
		Handler: si,
	}

	router.GET(baseURL+"/organizations/:organizationID/extensions", wrapper.ListExtensions)
	router.GET(baseURL+"/organizations/:organizationID/githubapp/installations", wrapper.ListGithubAppInstallations)
	router.POST(baseURL+"/organizations/:organizationID/githubapp/installations", wrapper.CreateGithubAppInstallation)
	router.PUT(baseURL+"/organizations/:organizationID/githubapp/installations/:githubInstallationID", wrapper.UpdateGithubAppInstallation)
	router.GET(baseURL+"/organizations/:organizationID/images", wrapper.ListImages)
	router.GET(baseURL+"/organizations/:organizationID/instanceTypes", wrapper.ListInstanceTypes)
	router.GET(baseURL+"/organizations/:organizationID/limits", wrapper.GetOrganizationLimits)
	router.GET(baseURL+"/organizations/:organizationID/projects", wrapper.ListProjects)
	router.POST(baseURL+"/organizations/:organizationID/projects", wrapper.CreateProject)
	router.GET(baseURL+"/organizations/:organizationID/projects/limits", wrapper.GetDefaultProjectLimits)
	router.DELETE(baseURL+"/organizations/:organizationID/projects/:projectID", wrapper.DeleteProject)
	router.GET(baseURL+"/organizations/:organizationID/projects/:projectID", wrapper.GetProject)
	router.PATCH(baseURL+"/organizations/:organizationID/projects/:projectID", wrapper.UpdateProject)
	router.GET(baseURL+"/organizations/:organizationID/projects/:projectID/backups", wrapper.ListBackups)
	router.GET(baseURL+"/organizations/:organizationID/projects/:projectID/backups/:backupID", wrapper.GetBackup)
	router.GET(baseURL+"/organizations/:organizationID/projects/:projectID/branches", wrapper.ListBranches)
	router.POST(baseURL+"/organizations/:organizationID/projects/:projectID/branches", wrapper.CreateBranch)
	router.DELETE(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID", wrapper.DeleteBranch)
	router.GET(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID", wrapper.DescribeBranch)
	router.PATCH(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID", wrapper.UpdateBranch)
	router.GET(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/credentials", wrapper.GetBranchCredentials)
	router.POST(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/credentials/rotate", wrapper.RotateBranchCredentials)
	router.DELETE(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/githubapp/repository", wrapper.DeleteGithubRepository)
	router.GET(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/githubapp/repository", wrapper.GetGithubRepository)
	router.POST(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/githubapp/repository", wrapper.CreateGithubRepository)
	router.PUT(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/githubapp/repository", wrapper.UpdateGithubRepository)
	router.POST(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/logs", wrapper.BranchLogs)
	router.POST(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/metrics", wrapper.BranchMetrics)
	router.GET(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/postgres-config", wrapper.GetBranchPostgresConfig)
	router.POST(baseURL+"/organizations/:organizationID/projects/:projectID/branches/:branchID/restore", wrapper.RestoreFromBackup)
	router.GET(baseURL+"/organizations/:organizationID/projects/:projectID/limits", wrapper.GetProjectLimits)
	router.GET(baseURL+"/organizations/:organizationID/regions", wrapper.ListRegions)

}

